INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (1, '2023-01-01', N'Lighthouse Sanctuary Impact Update - January 2023', N'Month of January 2023: 60 residents supported across 9 safehouses. PHP 1,380 raised (13% of PHP 11,000 monthly target). Funding gap: PHP 9,620. Critical funding month at 13% of target. The PHP 9,620 shortfall forced suspension of outreach activities and deferred facility maintenance. 60 residents were sustained on essential services only.', N'{"type": "monthly", "month": "2023-01", "donations_total_php": 1379.92, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 12.5, "funding_gap_php": 9620.08, "allocation_breakdown": {"Wellbeing": 941.91, "Outreach": 616.42, "Education": 515.14, "Operations": 169.46, "Transport": 351.13, "Maintenance": 359.33}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 1, "incidents_total": 0, "incidents_critical": 0, "challenge": "Critical funding month at 13% of target. The PHP 9,620 shortfall forced suspension of outreach activities and deferred facility maintenance. 60 residents were sustained on essential services only.", "avg_health_score": 3.03, "avg_education_progress": 33.9}', 1, '2023-01-01');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (2, '2023-02-01', N'Lighthouse Sanctuary Impact Update - February 2023', N'Month of February 2023: 60 residents supported across 9 safehouses. PHP 2,065 raised (19% of PHP 11,000 monthly target). Funding gap: PHP 8,935. Critical funding month at 19% of target. The PHP 8,935 shortfall forced suspension of outreach activities and deferred facility maintenance. 60 residents were sustained on essential services only. Counseling and mental health, facility maintenance and repairs received no allocation this month.', N'{"type": "monthly", "month": "2023-02", "donations_total_php": 2065.15, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 18.8, "funding_gap_php": 8934.85, "allocation_breakdown": {"Education": 1684.16, "Operations": 8.52, "Transport": 19.07}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 3, "incidents_total": 0, "incidents_critical": 0, "challenge": "Critical funding month at 19% of target. The PHP 8,935 shortfall forced suspension of outreach activities and deferred facility maintenance. 60 residents were sustained on essential services only. Counseling and mental health, facility maintenance and repairs received no allocation this month.", "avg_health_score": 3.13, "avg_education_progress": 51.05}', 1, '2023-02-01');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (3, '2023-03-01', N'Lighthouse Sanctuary Impact Update - March 2023', N'Month of March 2023: 60 residents supported across 9 safehouses. PHP 9,578 raised (87% of PHP 11,000 monthly target). Funding gap: PHP 1,422. Strong month at 87% funding coverage — PHP 1,422 below full target. 60 residents fully supported. Minor constraints in facility maintenance and repairs did not impact core services.', N'{"type": "monthly", "month": "2023-03", "donations_total_php": 9577.83, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 87.1, "funding_gap_php": 1422.17, "allocation_breakdown": {"Transport": 1860.46, "Wellbeing": 1796.89, "Operations": 4107.93, "Education": 1973.56, "Maintenance": 387.31, "Outreach": 695.6}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 3, "incidents_total": 0, "incidents_critical": 0, "challenge": "Strong month at 87% funding coverage \u2014 PHP 1,422 below full target. 60 residents fully supported. Minor constraints in facility maintenance and repairs did not impact core services.", "avg_health_score": 3.16, "avg_education_progress": 60.57}', 1, '2023-03-01');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (4, '2023-04-01', N'Lighthouse Sanctuary Impact Update - April 2023', N'Month of April 2023: 60 residents supported across 9 safehouses. PHP 5,401 raised (49% of PHP 11,000 monthly target). Funding gap: PHP 5,599. Funding gap of PHP 5,599 (49% coverage) constrained operations. Transportation and family visits was the most under-resourced program area. Staff prioritised direct care for 60 residents; non-essential activities were scaled back. 1 critical behavioural incident(s) this month underscored the urgent need for expanded mental-health staffing — a gap we cannot fill without additional donor support.', N'{"type": "monthly", "month": "2023-04", "donations_total_php": 5401.47, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 49.1, "funding_gap_php": 5598.53, "allocation_breakdown": {"Maintenance": 1677.73, "Education": 797.32, "Outreach": 496.04, "Operations": 3141.24, "Transport": 4.15, "Wellbeing": 634.14}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 3, "incidents_total": 1, "incidents_critical": 1, "challenge": "Funding gap of PHP 5,599 (49% coverage) constrained operations. Transportation and family visits was the most under-resourced program area. Staff prioritised direct care for 60 residents; non-essential activities were scaled back. 1 critical behavioural incident(s) this month underscored the urgent need for expanded mental-health staffing \u2014 a gap we cannot fill without additional donor support.", "avg_health_score": 3.2, "avg_education_progress": 69.15}', 1, '2023-04-01');
