INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (6, '2023-06-01', N'Lighthouse Sanctuary Impact Update - June 2023', N'Month of June 2023: 60 residents supported across 9 safehouses. PHP 1,307 raised (12% of PHP 11,000 monthly target). Funding gap: PHP 9,693. Critical funding month at 12% of target. The PHP 9,693 shortfall forced suspension of outreach activities and deferred facility maintenance. 60 residents were sustained on essential services only. Community outreach and referrals received no allocation this month.', N'{"type": "monthly", "month": "2023-06", "donations_total_php": 1306.86, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 11.9, "funding_gap_php": 9693.14, "allocation_breakdown": {"Wellbeing": 2094.28, "Maintenance": 808.5, "Education": 325.12, "Operations": 1282.95, "Transport": 332.99}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 3, "incidents_total": 1, "incidents_critical": 1, "challenge": "Critical funding month at 12% of target. The PHP 9,693 shortfall forced suspension of outreach activities and deferred facility maintenance. 60 residents were sustained on essential services only. Community outreach and referrals received no allocation this month.", "avg_health_score": 3.23, "avg_education_progress": 78.91}', 1, '2023-06-01');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (7, '2023-07-01', N'Lighthouse Sanctuary Impact Update - July 2023', N'Month of July 2023: 60 residents supported across 9 safehouses. PHP 6,592 raised (60% of PHP 11,000 monthly target). Funding gap: PHP 4,408. Partial funding at 60% of monthly target (PHP 4,408 short). All 60 residents received full care, but planned investment in facility maintenance and repairs was postponed to the following month.', N'{"type": "monthly", "month": "2023-07", "donations_total_php": 6592.33, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 59.9, "funding_gap_php": 4407.67, "allocation_breakdown": {"Education": 2078.19, "Operations": 738.49, "Transport": 3450.57, "Maintenance": 19.2, "Wellbeing": 558.58, "Outreach": 687.39}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 3, "incidents_total": 0, "incidents_critical": 0, "challenge": "Partial funding at 60% of monthly target (PHP 4,408 short). All 60 residents received full care, but planned investment in facility maintenance and repairs was postponed to the following month.", "avg_health_score": 3.19, "avg_education_progress": 79.46}', 1, '2023-07-01');
