INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (11, '2023-11-01', N'Lighthouse Sanctuary Impact Update - November 2023', N'Month of November 2023: 60 residents supported across 9 safehouses. PHP 6,302 raised (57% of PHP 11,000 monthly target). Funding gap: PHP 4,698. Partial funding at 57% of monthly target (PHP 4,698 short). All 60 residents received full care, but planned investment in counseling and mental health was postponed to the following month. Note: 3 incidents recorded this month (RunawayAttempt, Security, SelfHarm), highlighting the ongoing need for trauma-informed care resources.', N'{"type": "monthly", "month": "2023-11", "donations_total_php": 6302.16, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 57.3, "funding_gap_php": 4697.84, "allocation_breakdown": {"Operations": 4733.74, "Outreach": 1958.62, "Transport": 307.41, "Wellbeing": 18.82, "Maintenance": 721.11, "Education": 697.89}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 1, "incidents_total": 3, "incidents_critical": 2, "challenge": "Partial funding at 57% of monthly target (PHP 4,698 short). All 60 residents received full care, but planned investment in counseling and mental health was postponed to the following month. Note: 3 incidents recorded this month (RunawayAttempt, Security, SelfHarm), highlighting the ongoing need for trauma-informed care resources.", "avg_health_score": 3.15, "avg_education_progress": 81.89}', 1, '2023-11-01');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (12, '2023-12-01', N'Lighthouse Sanctuary Impact Update - December 2023', N'Month of December 2023: 60 residents supported. PHP 17,960 raised — 163% of target (PHP 6,960 surplus). Fully funded month (163% of target). All 60 residents received complete services across every program area. 1 new resident(s) admitted; shelters operating at high capacity. Surplus of PHP 6,960 reserved for maintenance and emergency response.', N'{"type": "monthly", "month": "2023-12", "donations_total_php": 17960.36, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 163.3, "funding_gap_php": -6960.36, "allocation_breakdown": {"Wellbeing": 5442.12, "Transport": 4461.74, "Operations": 6085.33, "Maintenance": 606.6, "Education": 1718.34, "Outreach": 681.04}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 1, "incidents_total": 2, "incidents_critical": 2, "challenge": "Fully funded month (163% of target). All 60 residents received complete services across every program area. 1 new resident(s) admitted; shelters operating at high capacity. Surplus of PHP 6,960 reserved for maintenance and emergency response.", "avg_health_score": 3.13, "avg_education_progress": 81.07}', 1, '2023-12-01');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (13, '2024-01-01', N'Lighthouse Sanctuary Impact Update - January 2024', N'Month of January 2024: 60 residents supported across 9 safehouses. PHP 5,840 raised (53% of PHP 11,000 monthly target). Funding gap: PHP 5,160. Partial funding at 53% of monthly target (PHP 5,160 short). All 60 residents received full care, but planned investment in transportation and family visits was postponed to the following month.', N'{"type": "monthly", "month": "2024-01", "donations_total_php": 5840.11, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 53.1, "funding_gap_php": 5159.89, "allocation_breakdown": {"Operations": 1525.08, "Education": 788.78, "Wellbeing": 2006.7, "Outreach": 265.83, "Maintenance": 1337.07, "Transport": 250.0}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 6, "incidents_total": 2, "incidents_critical": 1, "challenge": "Partial funding at 53% of monthly target (PHP 5,160 short). All 60 residents received full care, but planned investment in transportation and family visits was postponed to the following month.", "avg_health_score": 3.08, "avg_education_progress": 74.59}', 1, '2024-01-01');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (14, '2024-02-01', N'Lighthouse Sanctuary Impact Update - February 2024', N'Month of February 2024: 60 residents supported across 9 safehouses. PHP 1,875 raised (17% of PHP 11,000 monthly target). Funding gap: PHP 9,125. Critical funding month at 17% of target. The PHP 9,125 shortfall forced suspension of outreach activities and deferred facility maintenance. 60 residents were sustained on essential services only. Transportation and family visits, community outreach and referrals received no allocation this month. Note: 3 incidents recorded this month (Behavioral, RunawayAttempt), highlighting the ongoing need for trauma-informed care resources.', N'{"type": "monthly", "month": "2024-02", "donations_total_php": 1875.32, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 17.0, "funding_gap_php": 9124.68, "allocation_breakdown": {"Education": 13.94, "Operations": 1754.67, "Maintenance": 1095.21, "Wellbeing": 538.29}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 2, "incidents_total": 3, "incidents_critical": 2, "challenge": "Critical funding month at 17% of target. The PHP 9,125 shortfall forced suspension of outreach activities and deferred facility maintenance. 60 residents were sustained on essential services only. Transportation and family visits, community outreach and referrals received no allocation this month. Note: 3 incidents recorded this month (Behavioral, RunawayAttempt), highlighting the ongoing need for trauma-informed care resources.", "avg_health_score": 3.1, "avg_education_progress": 73.95}', 1, '2024-02-01');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (15, '2024-03-01', N'Lighthouse Sanctuary Impact Update - March 2024', N'Month of March 2024: 60 residents supported across 9 safehouses. PHP 2,776 raised (25% of PHP 11,000 monthly target). Funding gap: PHP 8,224. Funding gap of PHP 8,224 (25% coverage) constrained operations. Counseling and mental health was the most under-resourced program area. Staff prioritised direct care for 60 residents; non-essential activities were scaled back. 2 critical behavioural incident(s) this month underscored the urgent need for expanded mental-health staffing — a gap we cannot fill without additional donor support. Note: 4 incidents recorded this month (Behavioral, PropertyDamage, RunawayAttempt, SelfHarm), highlighting the ongoing need for trauma-informed care resources.', N'{"type": "monthly", "month": "2024-03", "donations_total_php": 2776.28, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 25.2, "funding_gap_php": 8223.72, "allocation_breakdown": {"Operations": 1562.15, "Wellbeing": 300.0, "Outreach": 716.84}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 0, "incidents_total": 4, "incidents_critical": 2, "challenge": "Funding gap of PHP 8,224 (25% coverage) constrained operations. Counseling and mental health was the most under-resourced program area. Staff prioritised direct care for 60 residents; non-essential activities were scaled back. 2 critical behavioural incident(s) this month underscored the urgent need for expanded mental-health staffing \u2014 a gap we cannot fill without additional donor support. Note: 4 incidents recorded this month (Behavioral, PropertyDamage, RunawayAttempt, SelfHarm), highlighting the ongoing need for trauma-informed care resources.", "avg_health_score": 3.11, "avg_education_progress": 76.67}', 1, '2024-03-01');
