01');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (17, '2024-05-01', N'Lighthouse Sanctuary Impact Update - May 2024', N'Month of May 2024: 60 residents supported across 9 safehouses. PHP 768 raised (7% of PHP 11,000 monthly target). Funding gap: PHP 10,232. Critical funding month at 7% of target. The PHP 10,232 shortfall forced suspension of outreach activities and deferred facility maintenance. 60 residents were sustained on essential services only. Daily operations and staffing, transportation and family visits received no allocation this month.', N'{"type": "monthly", "month": "2024-05", "donations_total_php": 767.63, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 7.0, "funding_gap_php": 10232.37, "allocation_breakdown": {"Wellbeing": 633.75, "Maintenance": 767.63, "Education": 772.22}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 2, "incidents_total": 0, "incidents_critical": 0, "challenge": "Critical funding month at 7% of target. The PHP 10,232 shortfall forced suspension of outreach activities and deferred facility maintenance. 60 residents were sustained on essential services only. Daily operations and staffing, transportation and family visits received no allocation this month.", "avg_health_score": 3.17, "avg_education_progress": 77.23}', 1, '2024-05-01');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (18, '2024-06-01', N'Lighthouse Sanctuary Impact Update - June 2024', N'Month of June 2024: 60 residents supported across 9 safehouses. PHP 3,712 raised (34% of PHP 11,000 monthly target). Funding gap: PHP 7,288. Funding gap of PHP 7,288 (34% coverage) constrained operations. Counseling and mental health was the most under-resourced program area. Staff prioritised direct care for 60 residents; non-essential activities were scaled back. 1 critical behavioural incident(s) this month underscored the urgent need for expanded mental-health staffing — a gap we cannot fill without additional donor support. Note: 3 incidents recorded this month (Medical, RunawayAttempt, Security), highlighting the ongoing need for trauma-informed care resources.', N'{"type": "monthly", "month": "2024-06", "donations_total_php": 3711.84, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 33.7, "funding_gap_php": 7288.16, "allocation_breakdown": {"Maintenance": 423.77, "Education": 1261.62, "Wellbeing": 287.5, "Operations": 1707.21, "Outreach": 427.1}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 2, "incidents_total": 3, "incidents_critical": 1, "challenge": "Funding gap of PHP 7,288 (34% coverage) constrained operations. Counseling and mental health was the most under-resourced program area. Staff prioritised direct care for 60 residents; non-essential activities were scaled back. 1 critical behavioural incident(s) this month underscored the urgent need for expanded mental-health staffing \u2014 a gap we cannot fill without additional donor support. Note: 3 incidents recorded this month (Medical, RunawayAttempt, Security), highlighting the ongoing need for trauma-informed care resources.", "avg_health_score": 3.12, "avg_education_progress": 71.84}', 1, '2024-06-01');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (19, '2024-07-01', N'Lighthouse Sanctuary Impact Update - July 2024', N'Month of July 2024: 60 residents supported across 9 safehouses. PHP 4,110 raised (37% of PHP 11,000 monthly target). Funding gap: PHP 6,890. Funding gap of PHP 6,890 (37% coverage) constrained operations. Transportation and family visits was the most under-resourced program area. Staff prioritised direct care for 60 residents; non-essential activities were scaled back. Note: 4 incidents recorded this month (Behavioral, PropertyDamage, Security), highlighting the ongoing need for trauma-informed care resources.', N'{"type": "monthly", "month": "2024-07", "donations_total_php": 4109.89, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 37.4, "funding_gap_php": 6890.11, "allocation_breakdown": {"Maintenance": 382.17, "Education": 2152.23, "Wellbeing": 609.08, "Transport": 286.8, "Operations": 286.8}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 1, "incidents_total": 4, "incidents_critical": 0, "challenge": "Funding gap of PHP 6,890 (37% coverage) constrained operations. Transportation and family visits was the most under-resourced program area. Staff prioritised direct care for 60 residents; non-essential activities were scaled back. Note: 4 incidents recorded this month (Behavioral, PropertyDamage, Security), highlighting the ongoing need for trauma-informed care resources.", "avg_health_score": 3.16, "avg_education_progress": 76.78}', 1, '2024-07-01');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (20, '2024-08-01', N'Lighthouse Sanctuary Impact Update - August 2024', N'Month of August 2024: 60 residents supported across 9 safehouses. PHP 7,299 raised (66% of PHP 11,000 monthly target). Funding gap: PHP 3,701. Partial funding at 66% of monthly target (PHP 3,701 short). All 60 residents received full care, but planned investment in facility maintenance and repairs was postponed to the following month. Note: 5 incidents recorded this month (Behavioral, ConflictWithPeer, RunawayAttempt), highlighting the ongoing need for trauma-informed care resources.', N'{"type": "monthly", "month": "2024-08", "donations_total_php": 7299.28, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 66.4, "funding_gap_php": 3700.72, "allocation_breakdown": {"Outreach": 602.49, "Operations": 3693.26, "Education": 971.81, "Maintenance": 6.53, "Wellbeing": 2447.64, "Transport": 7.76}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 2, "incidents_total": 5, "incidents_critical": 1, "challenge": "Partial funding at 66% of monthly target (PHP 3,701 short). All 60 residents received full care, but planned investment in facility maintenance and repairs was postponed to the following month. Note: 5 incidents recorded this month (Behavioral, ConflictWithPeer, RunawayAttempt), highlighting the ongoing need for trauma-informed care resources.", "avg_health_score": 3.15, "avg_education_progress": 76.61}', 1, '2024-08-01');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (21, '2024-09-01', N'Lighthouse Sanctuary Impact Update - September 2024', N'Month of September 2024: 60 residents supported across 9 safehouses. PHP 8,021 raised (73% of PHP 11,000 monthly target). Funding gap: PHP 2,979. Partial funding at 73% of monthly target (PHP 2,979 short). All 60 residents received full care, but planned investment in counseling and mental health was postponed to the following month. Note: 6 incidents recorded this month (RunawayAttempt, Security, SelfHarm), highlighting the ongoing need for trauma-informed care resources.', N'{"type": "monthly", "month": "2024-09", "donations_total_php": 8020.51, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 72.9, "funding_gap_php": 2979.49, "allocation_breakdown": {"Operations": 2666.39, "Education": 3948.38, "Maintenance": 1641.51, "Transport": 380.15, "Wellbeing": 235.77}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 1, "incidents_total": 6, "incidents_critical": 5, "challenge": "Partial funding at 73% of monthly target (PHP 2,979 short). All 60 residents received full care, but planned investment in counseling and mental health was postponed to the following month. Note: 6 incidents recorded this month (RunawayAttempt, Security, SelfHarm), highlighting the ongoing need for trauma-informed care resources.", "avg_health_score": 3.12, "avg_education_progress": 81.05}', 1, '2024-09-01');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (22, '2024-10-01', N'Lighthouse Sanctuary Impact Update - October 2024', N'Month of October 2024: 60 residents supported. PHP 13,284 raised — 121% of target (PHP 2,284 surplus). Fully funded month (121% of target). All 60 residents received complete services across every program area. 3 new resident(s) admitted; shelters operating at high capacity. Surplus of PHP 2,284 reserved for maintenance and emergency response. Note: 4 incidents recorded this month (ConflictWithPeer, PropertyDamage, RunawayAttempt, Security), highlighting the ongoing need for trauma-informed care resources.', N'{"type": "monthly", "month": "2024-10", "donations_total_php": 13284.48, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 120.8, "funding_gap_php": -2284.48, "allocation_breakdown": {"Transport": 5387.49, "Wellbeing": 4048.63, "Operations": 1258.98, "Education": 2477.5, "Maintenance": 1975.17, "Outreach": 1281.11}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 3, "incidents_total": 4, "incidents_critical": 1, "challenge": "Fully funded month (121% of target). All 60 residents received complete services across every program area. 3 new resident(s) admitted; shelters operating at high capacity. Surplus of PHP 2,284 reserved for maintenance and emergency response. Note: 4 incidents recorded this month (ConflictWithPeer, PropertyDamage, RunawayAttempt, Security), highlighting the ongoing need for trauma-informed care resources.", "avg_health_score": 3.1, "avg_education_progress": 75.73}', 1, '2024-10-01');
