INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (34, '2025-10-01', N'Lighthouse Sanctuary Impact Update - October 2025', N'Month of October 2025: 60 residents supported across 9 safehouses. PHP 7,802 raised (71% of PHP 11,000 monthly target). Funding gap: PHP 3,198. Partial funding at 71% of monthly target (PHP 3,198 short). All 60 residents received full care, but planned investment in community outreach and referrals was postponed to the following month. Note: 3 incidents recorded this month (Medical, Security, SelfHarm), highlighting the ongoing need for trauma-informed care resources.', N'{"type": "monthly", "month": "2025-10", "donations_total_php": 7802.06, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 70.9, "funding_gap_php": 3197.94, "allocation_breakdown": {"Transport": 2434.58, "Education": 1782.75, "Outreach": 1381.24, "Maintenance": 2366.18, "Operations": 2506.32, "Wellbeing": 1582.74}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 0, "incidents_total": 3, "incidents_critical": 1, "challenge": "Partial funding at 71% of monthly target (PHP 3,198 short). All 60 residents received full care, but planned investment in community outreach and referrals was postponed to the following month. Note: 3 incidents recorded this month (Medical, Security, SelfHarm), highlighting the ongoing need for trauma-informed care resources.", "avg_health_score": 3.31, "avg_education_progress": 85.45}', 1, '2025-10-01');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (35, '2025-11-01', N'Lighthouse Sanctuary Impact Update - November 2025', N'Month of November 2025: 60 residents supported. PHP 12,203 raised — 111% of target (PHP 1,203 surplus). Fully funded month (111% of target). All 60 residents received complete services across every program area. Surplus of PHP 1,203 reserved for maintenance and emergency response. Note: 6 incidents recorded this month (Behavioral, Medical, RunawayAttempt, SelfHarm), highlighting the ongoing need for trauma-informed care resources.', N'{"type": "monthly", "month": "2025-11", "donations_total_php": 12202.61, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 110.9, "funding_gap_php": -1202.61, "allocation_breakdown": {"Education": 3621.85, "Transport": 608.35, "Wellbeing": 2532.55, "Operations": 2513.86, "Outreach": 3143.17, "Maintenance": 469.23}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 0, "incidents_total": 6, "incidents_critical": 4, "challenge": "Fully funded month (111% of target). All 60 residents received complete services across every program area. Surplus of PHP 1,203 reserved for maintenance and emergency response. Note: 6 incidents recorded this month (Behavioral, Medical, RunawayAttempt, SelfHarm), highlighting the ongoing need for trauma-informed care resources.", "avg_health_score": 3.34, "avg_education_progress": 82.01}', 1, '2025-11-01');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (36, '2025-12-01', N'Lighthouse Sanctuary Impact Update - December 2025', N'Month of December 2025: 60 residents supported across 9 safehouses. PHP 9,862 raised (90% of PHP 11,000 monthly target). Funding gap: PHP 1,138. Strong month at 90% funding coverage — PHP 1,138 below full target. 60 residents fully supported. Minor constraints in facility maintenance and repairs did not impact core services. Note: 6 incidents recorded this month (ConflictWithPeer, RunawayAttempt, SelfHarm), highlighting the ongoing need for trauma-informed care resources.', N'{"type": "monthly", "month": "2025-12", "donations_total_php": 9862.44, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 89.7, "funding_gap_php": 1137.56, "allocation_breakdown": {"Education": 6445.25, "Transport": 2460.55, "Operations": 877.74, "Outreach": 375.53, "Wellbeing": 560.53, "Maintenance": 150.0}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 0, "incidents_total": 6, "incidents_critical": 4, "challenge": "Strong month at 90% funding coverage \u2014 PHP 1,138 below full target. 60 residents fully supported. Minor constraints in facility maintenance and repairs did not impact core services. Note: 6 incidents recorded this month (ConflictWithPeer, RunawayAttempt, SelfHarm), highlighting the ongoing need for trauma-informed care resources.", "avg_health_score": 3.38, "avg_education_progress": 79.53}', 1, '2025-12-01');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (37, '2026-01-01', N'Lighthouse Sanctuary Impact Update - January 2026', N'Month of January 2026: 60 residents supported across 9 safehouses. PHP 2,528 raised (23% of PHP 11,000 monthly target). Funding gap: PHP 8,472. Funding gap of PHP 8,472 (23% coverage) constrained operations. Facility maintenance and repairs was the most under-resourced program area. Staff prioritised direct care for 60 residents; non-essential activities were scaled back. 1 critical behavioural incident(s) this month underscored the urgent need for expanded mental-health staffing — a gap we cannot fill without additional donor support.', N'{"type": "monthly", "month": "2026-01", "donations_total_php": 2527.99, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 23.0, "funding_gap_php": 8472.01, "allocation_breakdown": {"Maintenance": 17.79, "Wellbeing": 1104.24, "Transport": 390.66, "Education": 1074.37, "Operations": 1222.74}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 0, "incidents_total": 2, "incidents_critical": 1, "challenge": "Funding gap of PHP 8,472 (23% coverage) constrained operations. Facility maintenance and repairs was the most under-resourced program area. Staff prioritised direct care for 60 residents; non-essential activities were scaled back. 1 critical behavioural incident(s) this month underscored the urgent need for expanded mental-health staffing \u2014 a gap we cannot fill without additional donor support.", "avg_health_score": 3.87, "avg_education_progress": 100.0}', 1, '2026-01-01');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (38, '2026-02-01', N'Lighthouse Sanctuary Impact Update - February 2026', N'Month of February 2026: 60 residents supported across 9 safehouses. PHP 3,382 raised (31% of PHP 11,000 monthly target). Funding gap: PHP 7,618. Funding gap of PHP 7,618 (31% coverage) constrained operations. Community outreach and referrals was the most under-resourced program area. Staff prioritised direct care for 60 residents; non-essential activities were scaled back.', N'{"type": "monthly", "month": "2026-02", "donations_total_php": 3382.25, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 30.7, "funding_gap_php": 7617.75, "allocation_breakdown": {"Transport": 594.72, "Operations": 1706.64, "Education": 806.23, "Maintenance": 709.25, "Outreach": 320.08}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 0, "incidents_total": 1, "incidents_critical": 0, "challenge": "Funding gap of PHP 7,618 (31% coverage) constrained operations. Community outreach and referrals was the most under-resourced program area. Staff prioritised direct care for 60 residents; non-essential activities were scaled back.", "avg_health_score": 3.94, "avg_education_progress": 100.0}', 1, '2026-02-01');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (39, '2026-03-01', N'Lighthouse Sanctuary Impact Update - March 2026', N'Month of March 2026: 60 residents supported across 9 safehouses. PHP 343 raised (3% of PHP 11,000 monthly target). Funding gap: PHP 10,657. Critical funding month at 3% of target. The PHP 10,657 shortfall forced suspension of outreach activities and deferred facility maintenance. 60 residents were sustained on essential services only. Education and schooling, counseling and mental health received no allocation this month.', N'{"type": "monthly", "month": "2026-03", "donations_total_php": 342.96, "monthly_operating_cost_php": 11000.0, "funding_coverage_pct": 3.1, "funding_gap_php": 10657.04, "allocation_breakdown": {"Operations": 171.48, "Outreach": 171.48}, "total_residents": 60, "capacity_total": 85, "capacity_utilization_pct": 70.6, "new_admissions": 0, "incidents_total": 0, "incidents_critical": 0, "challenge": "Critical funding month at 3% of target. The PHP 10,657 shortfall forced suspension of outreach activities and deferred facility maintenance. 60 residents were sustained on essential services only. Education and schooling, counseling and mental health received no allocation this month."}', 1, '2026-03-01');
