INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (51, '2023-12-31', N'Lighthouse Sanctuary 2023 Annual Impact Report', N'2023 Annual Report — Lighthouse Sanctuary. PHP 67,565 raised (51% of PHP 132,000 annual budget). 26 new residents admitted. 9 total incidents recorded (6 critical). Highest-giving month: December. Lowest-giving month: June. A difficult year financially — PHP 64,435 below the PHP 132,000 annual operating budget (51% coverage). 8 of 12 months fell below 50% funding, requiring repeated cutbacks to facility maintenance and repairs and outreach activities. We estimate that full funding would have allowed us to shelter an additional 12 girls and expand to 2 new communities.', N'{"type": "annual_summary", "year": 2023, "donations_total_php": 67564.88, "annual_operating_budget_php": 132000.0, "funding_coverage_pct": 51.2, "funding_gap_php": 64435.12, "months_below_50pct_funding": 8, "allocation_breakdown": {"Operations": 25478.44, "Outreach": 7095.24, "Wellbeing": 14878.55, "Education": 17603.1, "Transport": 14492.79, "Maintenance": 5764.6}, "best_funding_month": "2023-12", "worst_funding_month": "2023-06", "peak_residents": 60, "new_admissions": 26, "incidents_total": 9, "incidents_critical": 6, "challenge": "A difficult year financially \u2014 PHP 64,435 below the PHP 132,000 annual operating budget (51% coverage). 8 of 12 months fell below 50% funding, requiring repeated cutbacks to facility maintenance and repairs and outreach activities. We estimate that full funding would have allowed us to shelter an additional 12 girls and expand to 2 new communities."}', 1, '2023-12-31');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (52, '2024-12-31', N'Lighthouse Sanctuary 2024 Annual Impact Report', N'2024 Annual Report — Lighthouse Sanctuary. PHP 78,951 raised (60% of PHP 132,000 annual budget). 25 new residents admitted. 40 total incidents recorded (17 critical). Highest-giving month: December. Lowest-giving month: May. A difficult year financially — PHP 53,049 below the PHP 132,000 annual operating budget (60% coverage). 6 of 12 months fell below 50% funding, requiring repeated cutbacks to community outreach and referrals and outreach activities. We estimate that full funding would have allowed us to shelter an additional 12 girls and expand to 2 new communities.', N'{"type": "annual_summary", "year": 2024, "donations_total_php": 78950.9, "annual_operating_budget_php": 132000.0, "funding_coverage_pct": 59.8, "funding_gap_php": 53049.1, "months_below_50pct_funding": 6, "allocation_breakdown": {"Wellbeing": 17479.29, "Operations": 18611.59, "Transport": 10841.09, "Maintenance": 16072.58, "Outreach": 5196.64, "Education": 20019.43}, "best_funding_month": "2024-12", "worst_funding_month": "2024-05", "peak_residents": 60, "new_admissions": 25, "incidents_total": 40, "incidents_critical": 17, "challenge": "A difficult year financially \u2014 PHP 53,049 below the PHP 132,000 annual operating budget (60% coverage). 6 of 12 months fell below 50% funding, requiring repeated cutbacks to community outreach and referrals and outreach activities. We estimate that full funding would have allowed us to shelter an additional 12 girls and expand to 2 new communities."}', 1, '2024-12-31');
INSERT INTO PublicImpactSnapshots (SnapshotId, SnapshotDate, Headline, SummaryText, MetricPayloadJson, IsPublished, PublishedAt) VALUES (53, '2025-12-31', N'Lighthouse Sanctuary 2025 Annual Impact Report', N'2025 Annual Report — Lighthouse Sanctuary. PHP 87,956 raised (67% of PHP 132,000 annual budget). 9 new residents admitted. 47 total incidents recorded (19 critical). Highest-giving month: August. Lowest-giving month: May. PHP 44,044 in unmet funding constrained our reach in 2025 (67% of target). 4 months required service-level adjustments. Facility maintenance and repairs was the most under-resourced area, receiving only PHP 7,330 across the year. Closing this gap would allow us to serve 66 residents and hire one additional full-time counselor.', N'{"type": "annual_summary", "year": 2025, "donations_total_php": 87955.56, "annual_operating_budget_php": 132000.0, "funding_coverage_pct": 66.6, "funding_gap_php": 44044.44, "months_below_50pct_funding": 4, "allocation_breakdown": {"Education": 27803.32, "Transport": 12733.52, "Operations": 19662.2, "Outreach": 13597.87, "Wellbeing": 19486.44, "Maintenance": 7330.02}, "best_funding_month": "2025-08", "worst_funding_month": "2025-05", "peak_residents": 60, "new_admissions": 9, "incidents_total": 47, "incidents_critical": 19, "challenge": "PHP 44,044 in unmet funding constrained our reach in 2025 (67% of target). 4 months required service-level adjustments. Facility maintenance and repairs was the most under-resourced area, receiving only PHP 7,330 across the year. Closing this gap would allow us to serve 66 residents and hire one additional full-time counselor."}', 1, '2025-12-31');